def _filtrar(documento, nf):
    base = dados["data"]
    resultados = [
        d for d in base
        if (not documento or d["Frete"].get("DOCUMENTO") == documento) and
           (not nf or d["Frete"].get("NF") == nf)
    ]
    return resultados

def _motivo_erro(documento, nf, resultados):
    # Se já há resultados, não há erro
    if resultados:
        return None

    base = dados["data"]

    # Testes parciais para entender o motivo
    if documento:
        matches_doc = [d for d in base if d["Frete"].get("DOCUMENTO") == documento]
        if not matches_doc:
            return "Documento não encontrado"

    if nf:
        matches_nf = [d for d in base if d["Frete"].get("NF") == nf]
        if not matches_nf:
            return "NF não localizada"

    if documento and nf:
        # Há documentos e NFs existentes isoladamente, mas a combinação não retornou
        return "Combinação de Documento e NF não encontrada"

    # Genérico
    return "Nenhum registro encontrado"

@app.route('/api/dados', methods=['GET'])
def get_dados():
    documento = request.args.get('DOCUMENTO')
    nf = request.args.get('NF')

    # Normalizar possíveis espaços
    documento = documento.strip() if isinstance(documento, str) else documento
    nf = nf.strip() if isinstance(nf, str) else nf

    resultados = _filtrar(documento, nf)
    mensagem = "OK" if resultados else "ERRO"
    motivo = _motivo_erro(documento, nf, resultados)

    resp = {"mensagem": mensagem, "data": resultados}
    if motivo:
        resp["motivo"] = motivo
    return jsonify(resp)

@app.route('/api/dados/<int:id>', methods=['GET'])
def get_dado_por_id(id):
    dado = next((item for item in dados["data"] if item["Frete"].get("ID") == id), None)
    if dado:
        return jsonify({"mensagem": "OK", "data": dado})
    else:
        return jsonify({"mensagem": "ERRO", "motivo": "ID não encontrado", "error": "Dado não encontrado"}), 404

if __name__ == '__main__':
    app.run(debug=True)
